// Fetch latest fb-post-* Gist with PAT (Code node — bypasses HTTP node sendHeaders schema bug)
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.github.com/gists?per_page=10',
  headers: {
    'Authorization': 'token ' + $env.GIST_PAT,
    'Accept': 'application/vnd.github+json',
    'User-Agent': 'n8n-content-orchestrator'
  },
  json: true
});

const arr = Array.isArray(response) ? response : [];
const fbGist = arr.find(g => (g.description || '').startsWith('fb-post-'));
if (!fbGist) {
  throw new Error('No fb-post-* Gist in latest 10. Available: ' + arr.slice(0, 3).map(g => g.description || '(no desc)').join(' | '));
}
const fileEntry = Object.values(fbGist.files)[0];
return [{
  json: {
    gist_id: fbGist.id,
    gist_html_url: fbGist.html_url,
    raw_url: fileEntry.raw_url,
    filename: fileEntry.filename,
    description: fbGist.description,
    created_at: fbGist.created_at
  }
}];

// Parse YAML frontmatter + extract ## 草稿 (or ## draft) section
const raw = $input.first().json.data || $input.first().json;
const rawText = typeof raw === 'string' ? raw : JSON.stringify(raw);

const fmMatch = rawText.match(/^---\s*\n([\s\S]*?)\n---\s*\n([\s\S]*)$/);
if (!fmMatch) throw new Error('No YAML frontmatter found in Gist content');

const fmText = fmMatch[1];
const body = fmMatch[2];

// Simple YAML parser (flat keys + string arrays only)
const meta = {};
fmText.split('\n').forEach(line => {
  const m = line.match(/^([a-z_]+):\s*(.*)$/);
  if (m) {
    let val = m[2].trim();
    if (val.startsWith('[') && val.endsWith(']')) {
      val = val.slice(1, -1).split(',').map(s => s.trim().replace(/^["']|["']$/g, ''));
    } else if (val.startsWith('"') && val.endsWith('"')) {
      val = val.slice(1, -1);
    } else if (!isNaN(val) && val !== '') {
      val = Number(val);
    }
    meta[m[1]] = val;
  }
});

// Extract draft segment (matches both ## 草稿 and ## draft)
const draftMatch = body.match(/##\s*(?:草稿|draft)\s*\n([\s\S]*?)(?=\n##\s|$)/i);
let draft = draftMatch ? draftMatch[1].trim() : body.trim();

return [{
  json: {
    metadata: meta,
    post_text: draft,
    post_text_chars: draft.length,
    format: meta.format || 'text',
    gist_id: $('Pick Latest fb-post Gist').first().json.gist_id,
    gist_url: $('Pick Latest fb-post Gist').first().json.gist_html_url
  }
}];

// Exchange system user token -> page-scoped token, then POST to /{page_id}/feed
// (System user tokens cannot directly POST; must exchange via /me/accounts first)
const SYS_USER_TOKEN = $env.FB_SYSTEM_USER_TOKEN;
const PAGE_ID = $env.FB_PAGE_ID;
const V = $env.FB_GRAPH_VERSION || 'v24.0';
const postText = $input.first().json.post_text;

if (!postText || !postText.trim()) {
  throw new Error('post_text is empty, cannot publish');
}

// Step 1: exchange system user token -> page-scoped access_token via /me/accounts
const accounts = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://graph.facebook.com/${V}/me/accounts`,
  qs: { fields: 'id,name,access_token', limit: 100, access_token: SYS_USER_TOKEN },
  json: true
});

const pages = accounts.data || [];
const page = pages.find(p => String(p.id) === String(PAGE_ID));
if (!page || !page.access_token) {
  throw new Error(`Page ${PAGE_ID} not in /me/accounts. Visible: ${pages.map(p => p.id + ' ' + p.name).join(' | ') || '(empty)'}`);
}

// Step 2: POST to /{page_id}/feed with page-scoped token
const post = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://graph.facebook.com/${V}/${PAGE_ID}/feed`,
  body: {
    message: postText,
    access_token: page.access_token
  },
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  json: true
});

const postId = post.id || '';
const [pageId, postPart] = postId.split('_');
return [{
  json: {
    success: true,
    fb_post_id: postId,
    fb_permalink: postPart ? `https://www.facebook.com/${pageId}/posts/${postPart}` : `https://www.facebook.com/${PAGE_ID}`,
    page_name: page.name,
    chars: postText.length,
    timestamp: new Date().toISOString()
  }
}];
